--- a/llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp
@@ -41,6 +41,23 @@
 #include "llvm/Transforms/Utils/ScalarEvolutionExpander.h"
 #include "llvm/Transforms/Utils/UnrollLoop.h"

+static bool isProvablyNonZero(const llvm::SCEV *S, llvm::ScalarEvolution #include "llvm/Transforms/Utils/UnrollLoop.h"SE, llvm::Loop *L) {
+  if (const auto *SC = llvm::dyn_cast<llvm::SCEVConstant>(S))
+    return !SC->getAPInt().isZero();
+  return SE.isKnownNonZero(S);
+}
+
+
+static bool isProvablyNonZero(const llvm::SCEV *S, llvm::ScalarEvolution &SE, llvm::Loop *L) {
+  // If S is a constant nonzero, it's fine.
+  if (const auto *SC = llvm::dyn_cast<llvm::SCEVConstant>(S))
+    return !SC->getAPInt().isZero();
+  // If S cannot be zero based on SCEV reasoning.
+  if (!SE.isKnownNonZero(S))
+    return false;
+  return true;
+}
+
 using namespace llvm;

